// Качество сигнала (3 полоски как на телефоне)
export const I_SIGNAL_QUALITY = ({ quality = 'unknown' }: { quality?: string } = {}) => {
    const barCount = quality === 'excellent' ? 3 : quality === 'good' ? 2 : quality === 'fair' ? 1 : 0;
    const color = quality === 'excellent' ? '#10b981' : quality === 'good' ? '#3b82f6' : quality === 'fair' ? '#f59e0b' : '#ef4444';
    return (
        <svg viewBox="0 0 20 16" width="16" height="16" fill={color} xmlns="http://www.w3.org/2000/svg">
            {/* 1-я полоска (нижняя) */}
            <rect x="2" y="10" width="3" height="6" rx="0.5" opacity={barCount >= 1 ? 1 : 0.3} />
            {/* 2-я полоска (средняя) */}
            <rect x="8.5" y="6" width="3" height="10" rx="0.5" opacity={barCount >= 2 ? 1 : 0.3} />
            {/* 3-я полоска (верхняя) */}
            <rect x="15" y="2" width="3" height="14" rx="0.5" opacity={barCount >= 3 ? 1 : 0.3} />
        </svg>
    );
};